Here's a refactor that removes duplication by extracting the shared transformation/validation logic and reusing it for both CSV and JSON:

import csv
import json

def _normalize_row(row):
    name = row['name'].strip().title()
    email = row['email'].strip().lower()
    age = int(row['age'])
    if age >= 18 and '@' in email:
        return {'name': name, 'email': email, 'age': age}
    return None

def _process_rows(rows):
    results = []
    for row in rows:
        normalized = _normalize_row(row)
        if normalized:
            results.append(normalized)
    return results

def process_csv(path):
    with open(path) as f:
        return _process_rows(csv.DictReader(f))

def process_json(path):
    with open(path) as f:
        return _process_rows(json.load(f))

