#!/usr/bin/env python3
"""
TCP port checker using sockets.

Usage:
  python port_check.py <host> <port> [-t TIMEOUT] [-q]

Exit codes:
  0 = port open
  1 = port not open (refused/timeout/error)
"""

import argparse
import socket
import sys


def valid_port(value: str) -> int:
    try:
        port = int(value)
    except ValueError:
        raise argparse.ArgumentTypeError("port must be an integer")
    if not (1 <= port <= 65535):
        raise argparse.ArgumentTypeError("port must be in range 1-65535")
    return port


def check_port(host: str, port: int, timeout: float = 3.0):
    """
    Returns (is_open: bool, reason: str|None)
    """
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True, None
    except socket.timeout:
        return False, "timeout"
    except ConnectionRefusedError:
        return False, "refused"
    except socket.gaierror as e:
        return False, f"dns_error: {e}"
    except OSError as e:
        # Covers network unreachable, no route to host, etc.
        return False, e.strerror or e.__class__.__name__


def main():
    parser = argparse.ArgumentParser(description="Check if a TCP port is open on a remote host.")
    parser.add_argument("host", help="Hostname or IP (IPv4 or IPv6)")
    parser.add_argument("port", type=valid_port, help="TCP port number")
    parser.add_argument("-t", "--timeout", type=float, default=3.0, help="Connection timeout in seconds (default: 3)")
    parser.add_argument("-q", "--quiet", action="store_true", help="Suppress output; rely on exit code only")
    args = parser.parse_args()

    is_open, reason = check_port(args.host, args.port, args.timeout)

    if not args.quiet:
        if is_open:
            print(f"{args.host}:{args.port} is OPEN")
        else:
            msg = f"{args.host}:{args.port} is CLOSED"
            if reason:
                msg += f" ({reason})"
            print(msg)

    sys.exit(0 if is_open else 1)


if __name__ == "__main__":
    main()

