def sort_list(a):
    n=len(a)
    def heapify(i,n):
        while True:
            l=2*i+1; r=l+1; m=i
            if l<n and a[l]>a[m]: m=l
            if r<n and a[r]>a[m]: m=r
            if m==i: break
            a[i],a[m]=a[m],a[i]; i=m
    for i in range(n//2-1,-1,-1): heapify(i,n)
    for end in range(n-1,0,-1): a[0],a[end]=a[end],a[0]; heapify(0,end)
    return a

